    ap_sync_ViT_Block_Core_U0_ap_ready <= (ap_sync_reg_ViT_Block_Core_U0_ap_ready or ViT_Block_Core_U0_ap_ready);
    ap_sync_axis_to_apuint_U0_ap_ready <= (axis_to_apuint_U0_ap_ready or ap_sync_reg_axis_to_apuint_U0_ap_ready);
    ap_sync_ready <= (ap_sync_axis_to_apuint_U0_ap_ready and ap_sync_ViT_Block_Core_U0_ap_ready);
    apuint_to_axis_U0_ap_continue <= ap_const_logic_1;
    apuint_to_axis_U0_ap_start <= start_for_apuint_to_axis_U0_empty_n;
    axis_to_apuint_U0_ap_continue <= ap_const_logic_1;
    axis_to_apuint_U0_ap_start <= ((ap_sync_reg_axis_to_apuint_U0_ap_ready xor ap_const_logic_1) and ap_start);
    gmem0_RID <= ap_const_lv1_0;
    gmem0_RLAST <= ap_const_logic_0;
    gmem0_RRESP <= ap_const_lv2_0;
    gmem0_RUSER <= ap_const_lv1_0;
    gmem1_RID <= ap_const_lv1_0;
    gmem1_RLAST <= ap_const_logic_0;
    gmem1_RRESP <= ap_const_lv2_0;
    gmem1_RUSER <= ap_const_lv1_0;
    in_r_TREADY <= axis_to_apuint_U0_in_r_TREADY;
    out_r_TDATA <= apuint_to_axis_U0_out_r_TDATA;
    out_r_TKEEP <= apuint_to_axis_U0_out_r_TKEEP;
    out_r_TLAST <= apuint_to_axis_U0_out_r_TLAST;
    out_r_TSTRB <= apuint_to_axis_U0_out_r_TSTRB;
    out_r_TVALID <= apuint_to_axis_U0_out_r_TVALID;
    start_for_apuint_to_axis_U0_din <= (0=>ap_const_logic_1, others=>'-');
end behav;
